deleted = 0
for conv in pawflow.list_conversations():
    cid = conv.get('conversation_id') or ''
    if not cid:
        continue
    if not pawflow.get_extra(cid, 'help_bot_user_key'):
        continue  # not a help-bot conversation
    if pawflow.is_conversation_expired(cid):
        pawflow.delete_conversation(cid)
        deleted += 1
result = 'swept ' + str(deleted)
